<script setup>import { onMounted, onUnmounted, ref } from 'vue'; import { useCirclesStore } from '../stores/circles'; const circles=useCirclesStore(); const body=ref(''); let timer; async function send(){ if(body.value.trim()){ await circles.send(body.value); body.value=''; } } async function createCircle(){ const name=prompt('Circle name'); if(name) await circles.create(name); } onMounted(async()=>{ await circles.load(); timer=setInterval(()=>circles.poll().catch(()=>{}), circles.pollInterval); }); onUnmounted(()=>clearInterval(timer));</script><template><main class="shell"><aside class="card"><h2>Circles</h2><button @click="createCircle">New Circle</button><button v-for="circle in circles.items" :key="circle.id" @click="circles.open(circle)">{{ circle.name }}</button><RouterLink to="/notifications">Notifications</RouterLink><RouterLink to="/profile">Profile</RouterLink></aside><section class="card chat"><h1>{{ circles.active?.name ?? 'Choose a circle' }}</h1><div class="messages"><article v-for="message in circles.messages" :key="message.id"><strong>{{ message.sender?.username }}</strong><p>{{ message.body }}</p></article></div><form @submit.prevent="send"><input v-model="body" placeholder="Message"><button>Send</button></form></section></main></template>
